// Tauri Android Build Configuration
// Auto-generated by Tauri CLI

import java.io.File

// Rust编译任务 - 在Gradle构建前编译Rust原生库
val rustTargets = listOf(
    "aarch64-linux-android",
    "armv7-linux-androideabi",
    "x86_64-linux-android",
    "i686-linux-android"
)

// 注册Rust构建任务
tasks.register("buildRust") {
    doLast {
        val rustRootDir = file("../../../")
        // Get NDK path from environment
        val ndkHome = System.getenv("ANDROID_NDK_HOME").let { 
            if (it.isNullOrBlank()) System.getenv("NDK_HOME") else it 
        } ?: throw GradleException("NDK not found. Set ANDROID_NDK_HOME or NDK_HOME")
        
        // 设置NDK交叉编译环境
        val targets = mapOf(
            "aarch64-linux-android" to "arm64-v8a",
            "armv7-linux-androideabi" to "armeabi-v7a",
            "x86_64-linux-android" to "x86_64",
            "i686-linux-android" to "x86"
        )
        
        val toolchainVersions = mapOf(
            "aarch64-linux-android" to "aarch64-linux-android",
            "armv7-linux-androideabi" to "arm-linux-androideabi",
            "x86_64-linux-android" to "x86_64-linux-android",
            "i686-linux-android" to "i686-linux-android"
        )
        
        val hostTag = when {
            org.gradle.internal.os.OperatingSystem.current().isLinux -> "linux-x86_64"
            org.gradle.internal.os.OperatingSystem.current().isMacOsX -> "darwin-x86_64"
            org.gradle.internal.os.OperatingSystem.current().isWindows -> "windows-x86_64"
            else -> throw GradleException("Unsupported host OS")
        }
        
        val minSdkVersion = 26
        
        for ((rustTarget, abi) in targets) {
            val toolchain = toolchainVersions[rustTarget]!!
            val toolchainBin = "${ndkHome}/toolchains/llvm/prebuilt/${hostTag}/bin"
            val cc = "${toolchainBin}/${toolchain}${minSdkVersion}-clang"
            val cxx = "${toolchainBin}/${toolchain}${minSdkVersion}-clang++"
            val ar = "${toolchainBin}/llvm-ar"
            
            val jniLibsDir = file("src/main/jniLibs/${abi}")
            jniLibsDir.mkdirs()
            
            @Suppress("DEPRECATION")
            exec {
                workingDir = rustRootDir
                environment("ANDROID_NDK_HOME", ndkHome)
                environment("NDK_HOME", ndkHome)
                environment("CARGO_NDK_ANDROID_TARGET", rustTarget)
                environment("CC_${rustTarget.replace("-", "_")}", cc)
                environment("CXX_${rustTarget.replace("-", "_")}", cxx)
                environment("AR_${rustTarget.replace("-", "_")}", ar)
                environment("CARGO_TARGET_${rustTarget.uppercase().replace("-", "_")}_LINKER", cc)
                
                commandLine(
                    "cargo", "ndk",
                    "-t", rustTarget,
                    "-p", "26",
                    "--", "build", "--release",
                    "--target", rustTarget
                )
            }
        }
    }
}

// 前端资源打包任务 - 将 Vite 构建产物复制到 Android assets 目录
tasks.register("buildFrontend") {
    doLast {
        val frontendDistDir = file("../../../../dist")
        val assetsDir = file("src/main/assets")

        if (!frontendDistDir.exists() || !frontendDistDir.isDirectory) {
            throw GradleException(
                "Frontend dist directory not found at ${frontendDistDir.absolutePath}. " +
                "Run 'npm run build' first."
            )
        }

        // 清空现有 assets
        assetsDir.deleteRecursively()
        assetsDir.mkdirs()

        // 复制前端构建产物
        frontendDistDir.copyRecursively(assetsDir, overwrite = true)
        logger.lifecycle("Copied frontend assets from ${frontendDistDir.absolutePath} to ${assetsDir.absolutePath}")
    }
}

// 将构建任务插入到构建流程
tasks.whenTaskAdded {
    if (name.contains("externalNativeBuild") || name.contains("mergeDebugJniLibFolders") || name.contains("mergeReleaseJniLibFolders")) {
        dependsOn("buildRust")
    }
    // 在合并 assets 前先构建前端
    if (name.contains("merge") && name.contains("Assets")) {
        dependsOn("buildFrontend")
    }
}